<?php require_once __DIR__.'/../includes/functions.php';require_admin();require_role('super_admin');if($_SERVER['REQUEST_METHOD']==='POST'){check_csrf();db()->prepare("UPDATE users SET role=?,status=? WHERE id=?")->execute([$_POST['role'],$_POST['status'],$_POST['id']]);flash('success','User updated');redirect('/admin/users.php');}$users=db()->query("SELECT * FROM users ORDER BY id DESC")->fetchAll();$roles=['member','sponsor','exhibitor','admin','super_admin','membership_admin','village_admin','finance_admin','content_admin'];include __DIR__.'/../includes/header.php';?><div class="admin"><?php include __DIR__.'/sidebar.php';?><main class="content"><h1>Users & Roles</h1><table><tr><th>Name</th><th>Email</th><th>Role</th><th>Status</th><th>Save</th></tr><?php foreach($users as $u):?><tr><form method="post"><input type="hidden" name="csrf" value="<?=csrf_token()?>"><td><?=h($u['name'])?></td><td><?=h($u['email'])?></td><td><select name="role"><?php foreach($roles as $r):?><option <?=$u['role']===$r?'selected':''?>><?=h($r)?></option><?php endforeach;?></select></td><td><select name="status"><option <?=$u['status']==='Active'?'selected':''?>>Active</option><option <?=$u['status']==='Suspended'?'selected':''?>>Suspended</option></select></td><td><input type="hidden" name="id" value="<?=h($u['id'])?>"><button>Save</button></td></form></tr><?php endforeach;?></table></main></div><?php include __DIR__.'/../includes/footer.php';?>